SELECT *
FROM character_items
WHERE item_value > 100;

SELECT characters.mob_identifier, character_stats.mob_level
FROM characters
INNER JOIN character_stats ON characters.character_id = character_stats.character_id;

SELECT mob_vita, mob_mana, mob_experience, mob_hit, mob_dam, mob_level, mob_mark, mob_strength, mob_agility, mob_intelligence, mob_stamina
FROM character_stats
WHERE character_id = 0;

SELECT * 
FROM character_relationships 
WHERE relationship_type = 'rival';

SELECT characters.mob_identifier, character_attributes.mob_might, character_attributes.mob_grace, character_attributes.mob_will
FROM characters
JOIN character_attributes ON characters.character_id = character_attributes.character_id;
